import time, functools
def timer(func):
 @functools.wraps(func)

def wrapper(args, **kwargs):
 start = time.perf_counter()
 result = func(args,
**kwargs)
 end = time.perf_counter()
 print(f'{func.name} took {end -
start:.4f} seconds')
 return result
 return wrapper

